namespace sv_bcba4f1e057f47e3ab26811396ba2c62.Models;

public class PersonalInfo
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
}

public class ExperienceEntry
{
    public string Company { get; set; } = "";
    public string Role { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferenceEntry
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string ContactInfo { get; set; } = "";
}

public class WizardData
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> Experience { get; set; } = [];
    public List<ReferenceEntry> References { get; set; } = [];
    public HashSet<int> CompletedSteps { get; set; } = [];
}

using System.Collections.Concurrent;
using sv_bcba4f1e057f47e3ab26811396ba2c62.Models;

namespace sv_bcba4f1e057f47e3ab26811396ba2c62.Services;

/// <summary>
/// Singleton store that holds wizard data keyed by session ID.
/// Both the static SSR layout and interactive pages resolve the same instance.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, (WizardData Data, DateTime LastAccessed)> _store = new();

    public WizardData GetOrCreate(string sessionId)
    {
        var entry = _store.AddOrUpdate(
            sessionId,
            _ => (new WizardData(), DateTime.UtcNow),
            (_, existing) => (existing.Data, DateTime.UtcNow));
        return entry.Data;
    }

    /// <summary>
    /// Remove entries older than maxAge to prevent unbounded growth.
    /// Call periodically from a background service or middleware.
    /// </summary>
    public void CleanupExpired(TimeSpan maxAge)
    {
        var cutoff = DateTime.UtcNow - maxAge;
        foreach (var key in _store.Keys)
        {
            if (_store.TryGetValue(key, out var entry) && entry.LastAccessed < cutoff)
                _store.TryRemove(key, out _);
        }
    }
}

