using Microsoft.AspNetCore.Components;
using sv_bcba4f1e057f47e3ab26811396ba2c62.Models;
using sv_bcba4f1e057f47e3ab26811396ba2c62.Services;

namespace sv_bcba4f1e057f47e3ab26811396ba2c62.Components;

/// <summary>
/// Base class for wizard pages. Handles resolving the wizard session ID
/// across the prerender → interactive transition and circuit reuse.
/// </summary>
public abstract class WizardPageBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateStore Store { get; set; } = default!;
    [Inject] protected WizardSession Session { get; set; } = default!;
    [Inject] protected NavigationManager Nav { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;

    protected WizardData Wizard { get; private set; } = new();
    protected abstract int StepNumber { get; }

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        // Resolve session ID from the best available source:
        // 1. Circuit-scoped service (set on a previous navigation in this circuit)
        // 2. PersistentComponentState (carried from prerender to interactive)
        // 3. HttpContext cookie (available during prerender)
        if (!string.IsNullOrEmpty(Session.SessionId))
        {
            // Already resolved from a prior page in this circuit — nothing to do.
        }
        else if (PersistentState.TryTakeFromJson<string>("WizardSessionId", out var persisted))
        {
            Session.SessionId = persisted;
        }
        else
        {
            var ctx = HttpContextAccessor.HttpContext;
            Session.SessionId =
                ctx?.Items["WizardSessionId"]?.ToString()
                ?? ctx?.Request.Cookies["WizardSessionId"];
        }

        if (!string.IsNullOrEmpty(Session.SessionId))
        {
            Wizard = Store.GetOrCreate(Session.SessionId);
        }
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("WizardSessionId", Session.SessionId);
        return Task.CompletedTask;
    }

    protected void CompleteStepAndNavigate(string nextUrl)
    {
        Wizard.CompletedSteps.Add(StepNumber);
        Nav.NavigateTo(nextUrl);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Step 1: Personal Info</PageTitle>

<h3>Step 1 — Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.PersonalInfo.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input class="form-control" type="email" @bind="Wizard.PersonalInfo.Email" />
</div>

<button class="btn btn-primary" @onclick='() => CompleteStepAndNavigate("/apply/experience")'>
    Next &rarr;
</button>

@code {
    protected override int StepNumber => 1;
}

@page "/apply/experience"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Step 2: Experience</PageTitle>

<h3>Step 2 — Work Experience</h3>

@for (var i = 0; i < Wizard.Experience.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Entry @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Wizard.Experience[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Role</label>
            <input class="form-control" @bind="Wizard.Experience[index].Role" />
        </div>
        <div class="mb-2">
            <label class="form-label">Duration</label>
            <input class="form-control" @bind="Wizard.Experience[index].Duration" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Experience</button>

<div>
    <a href="/apply/personal-info" class="btn btn-outline-secondary me-2">&larr; Back</a>
    <button class="btn btn-primary" @onclick='() => CompleteStepAndNavigate("/apply/references")'>
        Next &rarr;
    </button>
</div>

@code {
    protected override int StepNumber => 2;

    private void AddEntry() => Wizard.Experience.Add(new());
    private void RemoveEntry(int index) => Wizard.Experience.RemoveAt(index);
}

@page "/apply/references"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Step 3: References</PageTitle>

<h3>Step 3 — References</h3>

@for (var i = 0; i < Wizard.References.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Reference @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="Wizard.References[index].Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="Wizard.References[index].Relationship" />
        </div>
        <div class="mb-2">
            <label class="form-label">Contact Info</label>
            <input class="form-control" @bind="Wizard.References[index].ContactInfo" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

<div>
    <a href="/apply/experience" class="btn btn-outline-secondary me-2">&larr; Back</a>
    <button class="btn btn-primary" @onclick='() => CompleteStepAndNavigate("/apply/review")'>
        Next &rarr;
    </button>
</div>

@code {
    protected override int StepNumber => 3;

    private void AddRef() => Wizard.References.Add(new());
    private void RemoveRef(int index) => Wizard.References.RemoveAt(index);
}

@page "/apply/review"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Step 4: Review</PageTitle>

<h3>Step 4 — Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @Wizard.PersonalInfo.Name</p>
    <p><strong>Email:</strong> @Wizard.PersonalInfo.Email</p>
</div>

<div class="card mb-3 p-3">
    <h5>Experience</h5>
    @if (Wizard.Experience.Count == 0)
    {
        <p class="text-muted">No experience entries added.</p>
    }
    @foreach (var exp in Wizard.Experience)
    {
        <div class="mb-2">
            <strong>@exp.Role</strong> at @exp.Company (@exp.Duration)
        </div>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (Wizard.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    @foreach (var r in Wizard.References)
    {
        <div class="mb-2">
            <strong>@r.Name</strong> — @r.Relationship (@r.ContactInfo)
        </div>
    }
</div>

<div>
    <a href="/apply/references" class="btn btn-outline-secondary me-2">&larr; Back</a>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    protected override int StepNumber => 4;
    private bool _submitted;

    private void Submit()
    {
        Wizard.CompletedSteps.Add(StepNumber);
        _submitted = true;
    }
}

