using Microsoft.AspNetCore.Components;
using sv_bcba4f1e057f47e3ab26811396ba2c62.Models;
using sv_bcba4f1e057f47e3ab26811396ba2c62.Services;

namespace sv_bcba4f1e057f47e3ab26811396ba2c62.Components;

/// <summary>
/// Base class for wizard pages. Handles resolving the wizard session ID
/// across the prerender → interactive transition and circuit reuse.
/// </summary>
public abstract class WizardPageBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateStore Store { get; set; } = default!;
    [Inject] protected WizardSession Session { get; set; } = default!;
    [Inject] protected NavigationManager Nav { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;

    protected WizardData Wizard { get; private set; } = new();
    protected abstract int StepNumber { get; }

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        // Resolve session ID from the best available source:
        // 1. Circuit-scoped service (set on a previous navigation in this circuit)
        // 2. PersistentComponentState (carried from prerender to interactive)
        // 3. HttpContext cookie (available during prerender)
        if (!string.IsNullOrEmpty(Session.SessionId))
        {
            // Already resolved from a prior page in this circuit — nothing to do.
        }
        else if (PersistentState.TryTakeFromJson<string>("WizardSessionId", out var persisted))
        {
            Session.SessionId = persisted;
        }
        else
        {
            var ctx = HttpContextAccessor.HttpContext;
            Session.SessionId =
                ctx?.Items["WizardSessionId"]?.ToString()
                ?? ctx?.Request.Cookies["WizardSessionId"];
        }

        if (!string.IsNullOrEmpty(Session.SessionId))
        {
            Wizard = Store.GetOrCreate(Session.SessionId);
        }
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("WizardSessionId", Session.SessionId);
        return Task.CompletedTask;
    }

    protected void CompleteStepAndNavigate(string nextUrl)
    {
        Wizard.CompletedSteps.Add(StepNumber);
        Nav.NavigateTo(nextUrl);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

