﻿@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject sv_bcba4f1e057f47e3ab26811396ba2c62.Services.WizardStateStore WizardStore
@inject IHttpContextAccessor HttpContextAccessor

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardRoute)
            {
                <div class="d-flex align-items-center gap-2 flex-grow-1">
                    @for (var i = 1; i <= TotalSteps; i++)
                    {
                        var step = i;
                        var isCurrent = step == CurrentStep;
                        var isCompleted = CompletedSteps.Contains(step);
                        var badgeClass = isCurrent ? "bg-primary"
                            : isCompleted ? "bg-success"
                            : "bg-secondary";

                        <a href="@StepUrl(step)"
                           class="badge @badgeClass text-decoration-none"
                           style="font-size: 0.85rem; padding: 0.4em 0.75em;">
                            @StepLabel(step)
                        </a>

                        @if (step < TotalSteps)
                        {
                            <span class="text-muted">›</span>
                        }
                    }
                    <span class="ms-auto text-muted small">Step @CurrentStep of @TotalSteps</span>
                </div>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

