using sv_bcba4f1e057f47e3ab26811396ba2c62.Components;
using sv_bcba4f1e057f47e3ab26811396ba2c62.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<WizardStateStore>();
// Scoped = per-circuit on Interactive Server; persists across navigations
builder.Services.AddScoped<WizardSession>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);

// Assign a wizard session cookie on /apply/* routes
app.Use(async (context, next) =>
{
    if (context.Request.Path.StartsWithSegments("/apply"))
    {
        if (context.Request.Cookies.TryGetValue("WizardSessionId", out var existingId))
        {
            context.Items["WizardSessionId"] = existingId;
        }
        else
        {
            var newId = Guid.NewGuid().ToString();
            context.Response.Cookies.Append("WizardSessionId", newId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                Secure = context.Request.IsHttps,
                MaxAge = TimeSpan.FromHours(2)
            });
            context.Items["WizardSessionId"] = newId;
        }
    }
    await next();
});

app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode();

app.Run();

