    {
        ["/apply/personal-info"] = 1,
        ["/apply/experience"]    = 2,
        ["/apply/references"]    = 3,
        ["/apply/review"]        = 4,
    };

    private bool IsWizardRoute => CurrentStep > 0;
    private int CurrentStep { get; set; }
    private HashSet<int> CompletedSteps { get; set; } = [];

    protected override void OnParametersSet()
    {
        var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
        CurrentStep = StepRoutes.GetValueOrDefault(path);

        if (IsWizardRoute)
        {
            var sessionId = HttpContextAccessor.HttpContext?.Items["WizardSessionId"]?.ToString()
                         ?? HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];

            CompletedSteps = string.IsNullOrEmpty(sessionId)
                ? []
                : WizardStore.GetOrCreate(sessionId).CompletedSteps;
        }
    }

    private static string StepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info",
    };

    private static string StepLabel(int step) => step switch
    {
        1 => "Personal Info",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => "",
    };
